// ============================================================================
// Virtual File System
// ============================================================================

namespace TestVFS {

struct VirtualFile {
    std::vector<char> content;
    bool is_directory = false;
};

static std::unordered_map<std::wstring, VirtualFile> g_files;

// Add a file to the virtual filesystem
inline void add_file(const wchar_t* path, const void* data, size_t size) {
    VirtualFile vf;
    const char* bytes = static_cast<const char*>(data);
    vf.content.assign(bytes, bytes + size);
    vf.is_directory = false;
    g_files[path] = std::move(vf);
}

// Add a text file (convenience)
inline void add_text_file(const wchar_t* path, const char* text) {
    add_file(path, text, strlen(text));
}

// Add a directory marker
inline void add_directory(const wchar_t* path) {
    VirtualFile vf;
    vf.is_directory = true;
    g_files[path] = std::move(vf);
}

// Check if file exists in VFS
inline bool exists(const wchar_t* path) {
    auto it = g_files.find(path);
    return it != g_files.end() && !it->second.is_directory;
}

// Check if directory exists in VFS
inline bool dir_exists(const wchar_t* path) {
    auto it = g_files.find(path);
    return it != g_files.end() && it->second.is_directory;
}

// Read file from VFS
inline size_t read(const wchar_t* path, char* buffer, size_t buffer_size) {
    auto it = g_files.find(path);
    if (it == g_files.end() || it->second.is_directory) return 0;

    const auto& content = it->second.content;
    size_t copy_size = (content.size() < buffer_size - 1) ? content.size() : buffer_size - 1;
    if (copy_size > 0) {
        memcpy(buffer, content.data(), copy_size);
    }
    buffer[copy_size] = '\0';
    return copy_size;
}

// Get file data pointer and size (for mmap simulation)
inline const void* get_data(const wchar_t* path, size_t* out_size) {
    auto it = g_files.find(path);
    if (it == g_files.end() || it->second.is_directory) {
        *out_size = 0;
        return nullptr;
    }
    *out_size = it->second.content.size();
    return it->second.content.data();
}

// Clear all virtual files (call between tests)
inline void clear() {
    g_files.clear();
}

} // namespace TestVFS


