namespace TestState {

// Reset all global state between tests
inline void reset_all() {
    TestVFS::clear();

    // Reset index lock state (if test build exposes it)
    #ifdef GITSMARTER_TEST_BUILD
    extern void test_reset_index_lock_state();
    test_reset_index_lock_state();
    #endif
}

// Setup/teardown helpers for tests that need them
struct ScopedReset {
    ScopedReset() = default;
    ~ScopedReset() { reset_all(); }
};

} // namespace TestState


