// Optional: VFS-backed I/O wrappers (for integration tests)
// ============================================================================

// These can be used to redirect I/O functions to VFS when testing
// Requires adding #ifdef GITSMARTER_TEST_BUILD sections to production code
// or using these as standalone test helpers

namespace TestIO {

// Simulate read_file() using VFS
inline size_t vfs_read_file(const wchar_t* path, char* buffer, size_t buffer_size) {
    return TestVFS::read(path, buffer, buffer_size);
}

// Simulate file_exists() using VFS
inline bool vfs_file_exists(const wchar_t* path) {
    return TestVFS::exists(path);
}

// Simulate dir_exists() using VFS
inline bool vfs_dir_exists(const wchar_t* path) {
    return TestVFS::dir_exists(path);
}

// Simulate mmap_open() using VFS
struct VFSMemoryMap {
    const void* data;
    size_t size;
};

inline VFSMemoryMap* vfs_mmap_open(const wchar_t* path) {
    size_t size;
    const void* data = TestVFS::get_data(path, &size);
    if (!data) return nullptr;

    auto* m = new VFSMemoryMap();
    m->data = data;
    m->size = size;
    return m;
}

inline void vfs_mmap_close(VFSMemoryMap* m) {
    delete m;
}

} // namespace TestIO
